-- COMPLETE OS DATABASE: All Windows Versions/Builds/Editions/Languages + Full OS Collection
-- AUTO-GENERATED: 2026-04-02
-- Total entries: 6021
-- Compatible with script.js parser.

CREATE TABLE IF NOT EXISTS os_families (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    name TEXT NOT NULL,
    icon TEXT NOT NULL
);

CREATE TABLE IF NOT EXISTS operating_systems (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    family_id INTEGER NOT NULL,
    name TEXT NOT NULL,
    version TEXT NOT NULL,
    codename TEXT,
    architecture TEXT NOT NULL DEFAULT '64-bit',
    size_gb REAL,
    description TEXT,
    release_date TEXT,
    eos_date TEXT,
    is_lts INTEGER DEFAULT 0,
    is_supported INTEGER DEFAULT 1,
    language TEXT DEFAULT 'English',
    edition TEXT DEFAULT 'Standard',
    download_url TEXT NOT NULL,
    FOREIGN KEY (family_id) REFERENCES os_families(id)
);














